import React, { useState, useEffect, useRef, useCallback } from 'react';
import { searchApi, SearchResult } from '../api/search';

function debounce<T extends (...args: any[]) => any>(fn: T, ms: number): T {
  let timer: ReturnType<typeof setTimeout>;
  return ((...args: any[]) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), ms);
  }) as any;
}

interface SearchAutocompleteProps {
  placeholder?: string;
  onSelect: (result: SearchResult) => void;
  minChars?: number;
}

export function SearchAutocomplete({
  placeholder = 'Search...',
  onSelect,
  minChars = 2,
}: SearchAutocompleteProps) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);

  const fetchResults = async (searchQuery: string) => {
    if (searchQuery.length < minChars) {
      setResults([]);
      setIsOpen(false);
      return;
    }
    setIsLoading(true);
    try {
      const data = await searchApi.search(searchQuery);
      setResults(data);
      setIsOpen(data.length > 0);
    } catch (err) {
      console.error('Search failed:', err);
      setResults([]);
    } finally {
      setIsLoading(false);
    }
  };

  const debouncedSearch = debounce(fetchResults, 300);

  useEffect(() => {
    debouncedSearch(query);
  }, [query]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!isOpen) return;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setSelectedIndex(i => Math.min(i + 1, results.length - 1));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setSelectedIndex(i => Math.max(i - 1, 0));
        break;
      case 'Enter':
        e.preventDefault();
        if (results[selectedIndex]) {
          onSelect(results[selectedIndex]);
          setQuery(results[selectedIndex].title);
          setIsOpen(false);
        }
        break;
      case 'Escape':
        setIsOpen(false);
        break;
    }
  };

  return (
    <div className="search-autocomplete">
      <input
        ref={inputRef}
        type="text"
        value={query}
        onChange={e => setQuery(e.target.value)}
        onKeyDown={handleKeyDown}
        onFocus={() => results.length > 0 && setIsOpen(true)}
        onBlur={() => setTimeout(() => setIsOpen(false), 200)}
        placeholder={placeholder}
        role="combobox"
        aria-expanded={isOpen}
      />
      {isLoading && <span className="spinner" />}
      {isOpen && (
        <ul className="suggestions-list" role="listbox">
          {results.map((result, idx) => (
            <li
              key={result.id}
              role="option"
              aria-selected={idx === selectedIndex}
              className={idx === selectedIndex ? 'selected' : ''}
              onMouseDown={() => {
                onSelect(result);
                setQuery(result.title);
                setIsOpen(false);
              } }
            >
              <span className="title">{result.title}</span>
              <span className="category">{result.category}</span>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

