import React, { useState, useCallback } from 'react';

interface StepConfig {
  id: string;
  title: string;
  fields: string[];
  validate?: (data: Record<string, any>) => string[];
}

interface FormWizardProps {
  steps: StepConfig[];
  onSubmit: (data: Record<string, any>) => Promise<void>;
  apiEndpoint: string;
}

function StepForm({ step, data, onChange }: {
  step: StepConfig;
  data: Record<string, any>;
  onChange: (field: string, value: any) => void;
}) {
  const [localData, setLocalData] = useState<Record<string, any>>({});

  const handleChange = (field: string) => (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setLocalData(prev => ({ ...prev, [field]: value }));
    onChange(field, value);
  };

  return (
    <div className="step-form">
      <h3>{step.title}</h3>
      {step.fields.map(field => (
        <div key={field} className="form-field">
          <label htmlFor={field}>{field}</label>
          <input
            id={field}
            value={localData[field] ?? data[field] ?? ''}
            onChange={handleChange(field)}
          />
        </div>
      ))}
    </div>
  );
}

export function FormWizard({ steps, onSubmit, apiEndpoint }: FormWizardProps) {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<Record<string, any>>({});
  const [errors, setErrors] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [draftSaved, setDraftSaved] = useState(false);

  const handleFieldChange = (field: string, value: any) => {
    setFormData({ ...formData, [field]: value });
  };

  const saveDraft = useCallback(async () => {
    try {
      await fetch(`${apiEndpoint}/drafts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ step: currentStep, data: formData }),
      });
      setDraftSaved(true);
    } catch {
      console.error('Failed to save draft');
    }
  }, [apiEndpoint, currentStep, formData]);

  const goToNext = () => {
    const step = steps[currentStep];
    setCurrentStep(currentStep + 1);
    if (step.validate) {
      const validationErrors = step.validate(formData);
      if (validationErrors.length > 0) {
        setErrors(validationErrors);
        return;
      }
    }
    setErrors([]);
  };

  const goToPrev = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
      setErrors([]);
    }
  };

  const handleSubmit = async () => {
    const step = steps[currentStep];
    if (step.validate) {
      const validationErrors = step.validate(formData);
      if (validationErrors.length > 0) {
        setErrors(validationErrors);
        return;
      }
    }

    setIsSubmitting(true);
    try {
      await fetch(apiEndpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });
      await onSubmit(formData);
    } catch (err) {
      setErrors(['Submission failed. Please try again.']);
    } finally {
      setIsSubmitting(false);
    }
  };

  const isLastStep = currentStep === steps.length - 1;

  return (
    <div className="form-wizard">
      <div className="step-indicators">
        {steps.map((step, idx) => (
          <div
            key={step.id}
            className={`step-indicator ${idx === currentStep ? 'active' : ''} ${idx < currentStep ? 'completed' : ''}`}
          >
            {step.title}
          </div>
        ))}
      </div>

      {errors.length > 0 && (
        <div className="error-list">
          {errors.map((err, i) => <p key={i} className="error">{err}</p>)}
        </div>
      )}

      <StepForm
        step={steps[currentStep]}
        data={formData}
        onChange={handleFieldChange}
      />

      <div className="wizard-actions">
        <button onClick={goToPrev} disabled={currentStep === 0}>Back</button>
        <button onClick={saveDraft} disabled={isSubmitting}>Save Draft</button>
        {isLastStep ? (
          <button onClick={handleSubmit} disabled={isSubmitting}>
            {isSubmitting ? 'Submitting...' : 'Submit'}
          </button>
        ) : (
          <button onClick={goToNext}>Next</button>
        )}
      </div>
    </div>
  );
}

