import React, { useState, useEffect, useRef } from 'react';

interface Notification {
  id: string;
  type: 'info' | 'warning' | 'error' | 'success';
  title: string;
  message: string;
  richBody?: string;
  timestamp: number;
  read: boolean;
}

interface NotificationCenterProps {
  userId: string;
  maxVisible?: number;
}

export function NotificationCenter({ userId, maxVisible = 50 }: NotificationCenterProps) {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [filter, setFilter] = useState<'all' | 'unread'>('all');
  const panelRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const eventSource = new EventSource(`/api/notifications/stream?userId=${userId}`);

    eventSource.onmessage = (event) => {
      try {
        const parsed: Notification = JSON.parse(event.data);
        setNotifications([...notifications, parsed]);
        showToast(parsed);
      } catch (err) {
        console.error('Failed to parse notification:', err);
      }
    };

    eventSource.onerror = () => {
      console.error('SSE connection error, reconnecting...');
    };
  }, [userId]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (panelRef.current && !panelRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const showToast = (notification: Notification) => {
    const toast = document.createElement('div');
    toast.className = `toast toast-${notification.type}`;
    toast.textContent = notification.title;
    document.body.appendChild(toast);
    setTimeout(() => toast.remove(), 5000);
  };

  const markAsRead = async (id: string) => {
    await fetch(`/api/notifications/${id}/read`, { method: 'PUT' });
    setNotifications(prev =>
      prev.map(n => n.id === id ? { ...n, read: true } : n)
    );
  };

  const markAllRead = async () => {
    await fetch(`/api/notifications/read-all`, { method: 'PUT' });
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  const unreadCount = notifications.filter(n => !n.read).length;
  const visibleNotifications = notifications
    .filter(n => filter === 'all' || !n.read)
    .slice(-maxVisible);

  return (
    <div className="notification-center" ref={panelRef}>
      <button
        className="notification-bell"
        onClick={() => setIsOpen(!isOpen)}
        aria-label={`Notifications (${unreadCount} unread)`}
      >
        <span className="bell-icon">&#128276;</span>
        {unreadCount > 0 && <span className="badge">{unreadCount}</span>}
      </button>

      {isOpen && (
        <div className="notification-panel">
          <div className="panel-header">
            <h3>Notifications</h3>
            <div className="filter-tabs">
              <button
                className={filter === 'all' ? 'active' : ''}
                onClick={() => setFilter('all')}
              >All</button>
              <button
                className={filter === 'unread' ? 'active' : ''}
                onClick={() => setFilter('unread')}
              >Unread</button>
            </div>
            <button onClick={markAllRead} className="mark-all">Mark all read</button>
          </div>

          <ul className="notification-list">
            {visibleNotifications.map(notification => (
              <li
                key={notification.id}
                className={`notification-item ${notification.read ? 'read' : 'unread'}`}
                onClick={() => markAsRead(notification.id)}
              >
                <div className="notification-header">
                  <span className={`type-badge ${notification.type}`}>{notification.type}</span>
                  <span className="title">{notification.title}</span>
                  <time>{new Date(notification.timestamp).toLocaleTimeString()}</time>
                </div>
                <p className="body">{notification.message}</p>
                {notification.richBody && (
                  <div
                    className="rich-body"
                    dangerouslySetInnerHTML={ { __html: notification.richBody } }
                  />
                )}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

