      console.error('Failed to parse notification:', err);
    }
  };

  eventSource.onerror = () => {
    console.error('SSE connection error, reconnecting...');
  };
}, [userId]);
```

**Issue 1: Stale Closure in onmessage handler**

The `onmessage` handler captures `notifications` from the initial render. When a new notification arrives:
1. First notification arrives → `setNotifications([...notifications, parsed])` → `notifications` is `[]`, so result is `[notification1]`
2. Second notification arrives → `setNotifications([...notifications, parsed])` → `notifications` is STILL `[]` (stale closure), so result is `[notification2]` instead of `[notification1, notification2]`

This is a classic React stale closure bug. The `notifications` array in the closure is the one from when the effect ran, not the current state.

**Issue 2: Missing EventSource cleanup**

The `useEffect` doesn't return a cleanup function to close the EventSource. When `userId` changes or component unmounts:
- Old EventSource remains open
- New EventSource is created
- Multiple connections accumulate

This causes:
- Memory leak
- Duplicate notifications (multiple connections receiving same events)
- Unnecessary server load

