  artist: string;
  url: string;
  duration: number;
}

interface MediaPlayerProps {
  playlist: Track[];
  autoPlay?: boolean;
}

export function MediaPlayer({ playlist, autoPlay = false }: MediaPlayerProps) {
  const [trackIndex, setTrackIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [volume, setVolume] = useState(0.8);
  const audioRef = useRef<HTMLAudioElement>(null);

  const currentTrack = playlist[trackIndex];

  useEffect(() => {
    if (autoPlay && audioRef.current) {
      audioRef.current.play();
      setIsPlaying(true);
    }
  }, [trackIndex]);

  useEffect(() => {
    let intervalId = setInterval(() => {
      if (audioRef.current && isPlaying) {
        setCurrentTime(audioRef.current.currentTime);
      }
    }, 100);

    return () => clearInterval(intervalId);
  }, [isPlaying]);

  const togglePlay = () => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play();
      setIsPlaying(true);
    }
  };

  const seek = (time: number) => {
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const changeVolume = (vol: number) => {
    setVolume(vol);
    if (audioRef.current) {
      audioRef.current.volume = vol;
    }
  };

  const playNext = () => {
    setTrackIndex(trackIndex + 1);
    setCurrentTime(0);
    setIsPlaying(true);
  };

  const playPrev = () => {
    if (currentTime > 3) {
      seek(0);
    } else if (trackIndex > 0) {
      setTrackIndex(trackIndex - 1);
      setCurrentTime(0);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = Math.floor(seconds % 60);
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="media-player">
      <audio
        ref={audioRef}
        src={currentTrack?.url}
        onEnded={playNext}
        onError={() => console.error('Failed to load track')}
      />

      <div className="now-playing">
        <h3>{currentTrack?.title ?? 'No track'}</h3>
        <p>{currentTrack?.artist ?? ''}</p>
      </div>

      <div className="controls">
        <button onClick={playPrev} aria-label="Previous">&#9198;</button>
        <button onClick={togglePlay} aria-label={isPlaying ? 'Pause' : 'Play'}>
          {isPlaying ? '⏸' : '▶'}
        </button>
        <button onClick={playNext} aria-label="Next">&#9197;</button>
      </div>

      <div className="progress">
        <span>{formatTime(currentTime)}</span>
        <input
          type="range"
          min={0}
          max={currentTrack?.duration ?? 0}
          value={currentTime}
          onChange={e => seek(Number(e.target.value))}
        />
        <span>{formatTime(currentTrack?.duration ?? 0)}</span>
      </div>

      <div className="volume">
        <input
          type="range"
          min={0}
          max={1}
          step={0.01}
          value={volume}
          onChange={e => changeVolume(Number(e.target.value))}
        />
      </div>

      <div className="playlist">
        <h4>Playlist</h4>
        <ul>
          {playlist.map((track, idx) => (
            <li
              key={track.id}
              className={idx === trackIndex ? 'active' : ''}
              onClick={() => {
                setTrackIndex(idx);
                setCurrentTime(0);
                setIsPlaying(true);
              } }
            >
              <span className="track-title">{track.title}</span>
              <span className="track-duration">{formatTime(track.duration)}</span>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

