public boolean deductBalance(String accountId, BigDecimal amount) {
    // Prefer atomic database update: UPDATE accounts SET balance = balance - amount WHERE id = accountId AND balance >= amount
    synchronized (accountId.intern()) {
        BigDecimal currentBalance = orderRepository.getBalance(accountId);
        if (currentBalance.compareTo(amount) >= 0) {
            BigDecimal newBalance = currentBalance.subtract(amount);
            orderRepository.setBalance(accountId, newBalance);
            logger.info("Deducted {} from account {}, new balance: {}", amount, accountId, newBalance);
            return true;
        }
        logger.warn("Insufficient balance for account {}", accountId);
        return false;
    }
}

