public void publishBatch(String topic, List<DomainEvent> events) {
    // This implementation leverages the async nature of the Kafka producer,
    // which will batch messages automatically based on its configuration (e.g., linger.ms, batch.size).
    for (DomainEvent event : events) {
        try {
            String payload = objectMapper.writeValueAsString(event);
            kafkaTemplate.send(topic, event.getAggregateId(), payload);
        } catch (Exception e) {
            logger.error("Failed to submit event {} to batch for topic {}: {}",
                event.getEventType(), topic, e.getMessage());
        }
    }
    logger.info("Submitted batch of {} events for publishing to {}", events.size(), topic);
}

