    `SELECT p.id, p.name, p.scope FROM permissions p
     JOIN user_permissions up ON p.id = up.permission_id
     WHERE up.user_id = $1`,
    [userId],
  );

  return {
    user,
    roles: permissions.map(p => p.name),
