response.existingCode:
async findUserWithAccess(userId: string): Promise<{ user: User; permissions: Permission[] } | null> {
  const user = await this.findById(userId);
  if (!user) return null;

  const permissions = await this.db.query<Permission>(
    `SELECT p.id, p.name, p.scope FROM permissions p
     JOIN user_permissions up ON p.id = up.permission_id
     WHERE up.user_id = $1`,
    [userId],
  );

  return {
    user,
    permissions,
  };
}

response.improvedCode:
async findUserWithAccess(
  userId: string,
): Promise<{ user: User; roles: string[]; permissions: Permission[] } | null> {
  const user = await this.findById(userId);
  if (!user) return null;

  const permissions = await this.db.query<Permission>(
    `SELECT p.id, p.name, p.scope FROM permissions p
     JOIN user_permissions up ON p.id = up.permission_id
     WHERE up.user_id = $1`,
    [userId],
  );

  // Preserve legacy contract for existing middleware until it is migrated.
  const roles = await this.db.query<{ name: string }>(
    `SELECT r.name FROM roles r
     JOIN user_roles ur ON r.id = ur.role_id
     WHERE ur.user_id = $1`,
    [userId],
  );

  return {
    user,
    roles: roles.map(r => r.name),
    permissions,
  };
}

