    [teamId],
  );
  return {
    members,
    totalMembers: members.length,
  };
}

response.improvedCode:
async getTeamMembers(
  teamId: string,
): Promise<{ members: User[]; memberCount: number; totalMembers: number }> {
  const members = await this.db.query<User>(
    'SELECT u.* FROM users u JOIN team_members tm ON u.id = tm.user_id WHERE tm.team_id = $1',
    [teamId],
  );
  const count = members.length;
  return {
    members,
    // Preserve legacy contract for existing TeamService consumers.
    memberCount: count,
    totalMembers: count,
  };
}

