async findUserWithAccess(userId: string): Promise<{ user: User; permissions: Permission[]; roles?: string[] } | null> {
  const user = await this.findById(userId);
  if (!user) return null;

  const permissions = await this.db.query<Permission>(
    `SELECT p.id, p.name, p.scope FROM permissions p
     JOIN user_permissions up ON p.id = up.permission_id
     WHERE up.user_id = $1`,
    [userId],
  );

  return {
    user,
    permissions,
    roles: permissions.map(p => p.name),
  };
}

