export function validateEmail(optsOrEmail: ValidateEmailOptions | string, strict?: boolean): boolean {
  let email: string;
  let strictMode: boolean;

  if (typeof optsOrEmail === 'string') {
    email = optsOrEmail;
    strictMode = strict ?? false;
  } else {
    email = optsOrEmail.email;
    strictMode = optsOrEmail.strict ?? false;
  }

  const regex = strictMode ? STRICT_EMAIL_REGEX : EMAIL_REGEX;
  return regex.test(email);
}

export function sanitizeInput(optsOrInput: SanitizeInputOptions | string, maxLength?: number): string {
  let input: string;
  let max: number;
  let stripHtml: boolean;

  if (typeof optsOrInput === 'string') {
    input = optsOrInput;
    max = maxLength ?? 10000;
    stripHtml = false;
  } else {
    input = optsOrInput.input;
    max = optsOrInput.maxLength ?? 10000;
    stripHtml = optsOrInput.stripHtml ?? false;
  }

  if (stripHtml) {
    input = input.replace(/<[^>]*>/g, '');
  }
  input = input.replace(/[<>"'&]/g, (ch) => `&#${ch.charCodeAt(0)};`);
  return input.slice(0, max);
}

export function parseDate(optsOrInput: ParseDateOptions | string, format?: string): Date {
  let input: string;
  let fmt: string;
  let timezone: string;

  if (typeof optsOrInput === 'string') {
    input = optsOrInput;
    fmt = format ?? 'ISO';
    timezone = 'UTC';
  } else {
    input = optsOrInput.input;
    fmt = optsOrInput.format ?? 'ISO';
    timezone = optsOrInput.timezone ?? 'UTC';
  }

  if (fmt === 'ISO') {
    return new Date(input);
  }
  return parseDateWithFormat(input, fmt, timezone);
}

