import { useState, useCallback, useMemo } from 'react';

type ValidationRule = {
  validate: (value: any, allValues: Record<string, any>) => boolean;
  message: string;
};

type FieldRules = Record<string, ValidationRule[]>;

interface ValidationState {
  fieldErrors: Record<string, string[]>;
  isValid: boolean;
  isDirty: boolean;
  touchedFields: Set<string>;
}

interface UseFormValidationOptions {
  rules: FieldRules;
  validateOnChange?: boolean;
  validateOnBlur?: boolean;
}

interface UseFormValidationReturn {
  fieldErrors: Record<string, string[]>;
  isValid: boolean;
  isDirty: boolean;
  validateField: (field: string, value: any, allValues: Record<string, any>) => string[];
  validateAll: (values: Record<string, any>) => boolean;
  resetValidation: () => void;
  touchField: (field: string) => void;
  isFieldTouched: (field: string) => boolean;
  getFieldError: (field: string) => string | undefined;
}

export function useFormValidation(options: UseFormValidationOptions): UseFormValidationReturn {
  const { rules, validateOnChange = true, validateOnBlur = true } = options;

  const [state, setState] = useState<ValidationState>({
    fieldErrors: {},
    isValid: true,
    isDirty: false,
    touchedFields: new Set(),
  });

  const validateField = useCallback((field: string, value: any, allValues: Record<string, any>) => {
    const fieldRules = rules[field] || [];
    const errors = fieldRules
      .filter(rule => !rule.validate(value, allValues))
      .map(rule => rule.message);

    setState(prev => ({
      ...prev,
      fieldErrors: { ...prev.fieldErrors, [field]: errors },
      isDirty: true,
    }));

    return errors;
  }, [rules]);

  const validateAll = useCallback((values: Record<string, any>) => {
    const allErrors: Record<string, string[]> = {};
    let valid = true;

    for (const [field, fieldRules] of Object.entries(rules)) {
      const errors = fieldRules
        .filter(rule => !rule.validate(values[field], values))
        .map(rule => rule.message);
      allErrors[field] = errors;
      if (errors.length > 0) valid = false;
    }

    setState(prev => ({
      ...prev,
      fieldErrors: allErrors,
      isValid: valid,
      isDirty: true,
    }));

    return valid;
  }, [rules]);

  const resetValidation = useCallback(() => {
    setState({ fieldErrors: {}, isValid: true, isDirty: false, touchedFields: new Set() });
  }, []);

  const touchField = useCallback((field: string) => {
    setState(prev => ({
      ...prev,
      touchedFields: new Set(prev.touchedFields).add(field),
    }));
  }, []);

  const isFieldTouched = useCallback((field: string) => {
    return state.touchedFields.has(field);
  }, [state.touchedFields]);

  const getFieldError = useCallback((field: string) => {
    const errors = state.fieldErrors[field];
    return errors && errors.length > 0 ? errors[0] : undefined;
  }, [state.fieldErrors]);

  return {
    fieldErrors: state.fieldErrors,
    isValid: state.isValid,
    isDirty: state.isDirty,
    validateField,
    validateAll,
    resetValidation,
    touchField,
    isFieldTouched,
    getFieldError,
  };
}

