private static final Set<String> ALLOWED_HOSTS = Set.of("api.example.com", "service.example.com");

public HttpResponse<String> get(String url) throws Exception {
    URI uri = URI.create(url);
    if (!ALLOWED_HOSTS.contains(uri.getHost())) {
        throw new IllegalArgumentException("URL host not in allowlist");
    }
    HttpRequest request = HttpRequest.newBuilder()
        .uri(uri)
        .timeout(Duration.ofSeconds(30))
        .GET()
        .build();
    return client.send(request, HttpResponse.BodyHandlers.ofString());
}

